          padding: "0 20px"
        }}
      >
        <button
          onClick={() =>
            setIsOpen(
              !isOpen
            )
          }
          style={{
            fontSize: "24px",
            background:
              "transparent",
            border: "none",
            color: "white",
            cursor: "pointer"
          }}
        >
          ☰
        </button>

        <h2
          style={{
            marginLeft:
              "20px"
          }}
